<?php include 'includes/db.php'; include 'includes/auth.php'; require_login(); include 'includes/header.php'; $uid=(int)$_SESSION['user_id']; $orders=mysqli_query($conn,"SELECT * FROM orders WHERE customer_id=$uid ORDER BY created_at DESC"); ?>
